import{_ as s,c as t,o as a,aj as i}from"./chunks/framework.BlveriQe.js";const u=JSON.parse('{"title":"Access Control","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/access-control.md","filePath":"getting-started/access-control.md"}'),r={name:"getting-started/access-control.md"};function n(o,e,l,d,h,c){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="access-control" tabindex="-1">Access Control <a class="header-anchor" href="#access-control" aria-label="Permalink to “Access Control”">​</a></h1><p>Server API calls in Primitive are gated by access rules written in <strong><a href="https://github.com/google/cel-spec" target="_blank" rel="noreferrer">CEL</a></strong> — a one-line expression evaluated against the authenticated caller. Database operations, real-time subscriptions, workflow invocation, management of groups and collections: one expression language, one identity context. Learn it once and you can read and write the access rules anywhere they appear.</p><h2 id="cel-in-sixty-seconds" tabindex="-1">CEL in Sixty Seconds <a class="header-anchor" href="#cel-in-sixty-seconds" aria-label="Permalink to “CEL in Sixty Seconds”">​</a></h2><p>A CEL expression is a one-line condition that evaluates to true or false:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">access = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;user.userId != &#39;&#39;&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                                  # any authenticated user</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">access = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;hasRole(&#39;admin&#39;) || hasRole(&#39;owner&#39;)&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # app admins</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">access = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;isMemberOf(&#39;team&#39;, params.teamId)&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # team members</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">access = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;params.createdBy == user.userId&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                    # the record&#39;s owner</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">access = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;size(memberGroups(&#39;team&#39;)) &gt; 0&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     # member of any team</span></span></code></pre></div><p>Standard operators work as you&#39;d expect: <code>==</code>, <code>!=</code>, <code>&lt;</code>, <code>&amp;&amp;</code>, <code>||</code>, <code>!</code>, <code>in</code>, plus functions like <code>size(...)</code>. String literals use single quotes inside TOML double-quoted strings.</p><h2 id="the-identity-context" tabindex="-1">The Identity Context <a class="header-anchor" href="#the-identity-context" aria-label="Permalink to “The Identity Context”">​</a></h2><p>Every CEL evaluation sees the authenticated caller:</p><table tabindex="0"><thead><tr><th>Variable / function</th><th>Meaning</th></tr></thead><tbody><tr><td><code>user.userId</code></td><td>The caller&#39;s user ID (empty string when unauthenticated)</td></tr><tr><td><code>user.role</code></td><td>The caller&#39;s app role</td></tr><tr><td><code>isAnonymous()</code></td><td>True when the caller has no account at all (an unauthenticated request). Write <code>!isAnonymous()</code> to require any signed-in member; relevant where anonymous access is possible, such as a <code>public</code> <a href="./blobs-and-files.html#access-presets">blob bucket</a></td></tr><tr><td><code>hasRole(role)</code></td><td>True if the caller&#39;s app role is <code>&quot;owner&quot;</code>, <code>&quot;admin&quot;</code>, or <code>&quot;member&quot;</code> as given (app-level role — distinct from the document <code>owner</code> <a href="./working-with-documents.html#sharing-documents">permission</a>)</td></tr><tr><td><code>isMemberOf(groupType, groupId)</code></td><td>True if the caller belongs to that exact group</td></tr><tr><td><code>memberGroups(groupType)</code></td><td>The list of group IDs of that type the caller belongs to</td></tr><tr><td><code>fromWorkflow()</code> / <code>fromWorkflow(key)</code></td><td>True when the call comes from the internal workflow runner (optionally a specific workflow) — gate an operation to server-side automation only</td></tr></tbody></table><p>Group membership is the workhorse: model teams, roles, and relationships as <a href="./users-and-groups.html">groups</a>, then write rules against membership instead of hard-coding user IDs. <code>isMemberOf(&#39;team&#39;, params.teamId)</code> stays correct as people join and leave; <code>userId == &#39;01ABC...&#39;</code> doesn&#39;t.</p><p>Each place a rule appears adds its own context on top — operation <code>params.*</code>, the <code>database.*</code> being accessed, the <code>record.*</code> being written. The feature pages document their specific variables. A rule at a site with a declared metadata manifest also gains <code>md.self.*</code> (and, where declared, <code>md.&lt;path&gt;.*</code> / <code>md.caller.*</code>) — see <a href="./resource-metadata.html">Resource Metadata</a>.</p><h3 id="a-rule-sees-identity-not-stored-data" tabindex="-1">A Rule Sees Identity, Not Stored Data <a class="header-anchor" href="#a-rule-sees-identity-not-stored-data" aria-label="Permalink to “A Rule Sees Identity, Not Stored Data”">​</a></h3><p>Every function above answers a question about the <em>caller</em> — their role, their group memberships, the operation&#39;s params. A rule has no way to read a database record. So an entitlement you want the server to enforce — a paid feature, a role gate — can&#39;t live as a flag on a row: storing <code>isSubscribed = true</code> and checking it in a rule doesn&#39;t work, because the rule can&#39;t read the row, and a flag no rule can check isn&#39;t enforced server-side (a client can call the operation regardless).</p><p>Model the entitlement as <strong>group membership</strong> instead, which a rule <em>can</em> check:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">access = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;isMemberOf(&#39;subscription&#39;, &#39;trialing&#39;) || isMemberOf(&#39;subscription&#39;, &#39;active&#39;)&quot;</span></span></code></pre></div><p>Maintain that membership from your billing source — add a member when a subscription starts, remove them when it lapses — and every rule that gates a paid feature becomes a one-line membership check.</p><h2 id="where-rules-appear" tabindex="-1">Where Rules Appear <a class="header-anchor" href="#where-rules-appear" aria-label="Permalink to “Where Rules Appear”">​</a></h2><table tabindex="0"><thead><tr><th>Surface</th><th>What the rule gates</th><th>Details</th></tr></thead><tbody><tr><td>Database operations (<code>access</code>, <code>defaultAccess</code>, per-param <code>access</code>)</td><td>Who can execute a query/mutation, or set a specific parameter</td><td><a href="./working-with-databases.html#access-control-with-cel">Working with Databases</a></td></tr><tr><td>Database subscriptions (<code>accessRule</code> + <code>filter</code>)</td><td>Who can subscribe, and which changes they receive</td><td><a href="./working-with-databases.html#real-time-subscriptions">Real-Time Subscriptions</a></td></tr><tr><td>Workflows (<code>accessRule</code>)</td><td>Who can start a run directly from a client</td><td><a href="./workflows.html#controlling-access-to-workflows">Controlling Access to Workflows</a></td></tr><tr><td>Server-stamped fields (trigger <code>when</code> conditions)</td><td>Whether a computed field applies to this write</td><td><a href="./working-with-databases.html#server-stamped-fields">Server-Stamped Fields</a></td></tr><tr><td>Blob buckets (<code>ruleSetId</code>)</td><td>Member-level access to a bucket&#39;s blobs, per operation</td><td><a href="./blobs-and-files.html#access-presets">Blobs and Files</a></td></tr><tr><td>Rule sets</td><td>Who can perform <strong>management operations</strong> on groups and collections</td><td>below</td></tr><tr><td>Metadata categories (<code>readRule</code> + <code>writeRule</code>)</td><td>Who can read or write one category of a resource&#39;s metadata</td><td><a href="./resource-metadata.html">Resource Metadata</a></td></tr></tbody></table><h2 id="rule-sets-governing-management-operations" tabindex="-1">Rule Sets: Governing Management Operations <a class="header-anchor" href="#rule-sets-governing-management-operations" aria-label="Permalink to “Rule Sets: Governing Management Operations”">​</a></h2><p>Data-access rules live on the operation they protect. <strong>Rule sets</strong> answer a different question: who may <em>manage</em> a platform resource — create groups of a type, add or remove members, edit or delete a collection. A rule set is a named bundle of CEL rules per management operation:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rule-sets</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;team-management&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --resource-type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> group</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --rules</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;group&quot;:  { &quot;create&quot;: &quot;true&quot;, &quot;edit&quot;: &quot;user.userId == group.createdBy&quot;, &quot;delete&quot;: &quot;user.userId == group.createdBy&quot; },</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;member&quot;: { &quot;create&quot;: &quot;isMemberOf(group.groupType, group.groupId)&quot;, &quot;edit&quot;: &quot;user.userId == group.createdBy&quot;, &quot;delete&quot;: &quot;user.userId == group.createdBy&quot; }</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  }&#39;</span></span></code></pre></div><p>Bind a rule set to a <strong>group type</strong> or <strong>collection type</strong> via its type config — in TOML (<code>config/group-type-configs/&lt;type&gt;.toml</code>, <code>config/collection-type-configs/&lt;type&gt;.toml</code>) or from the client (<code>client.groupTypeConfigs.create({ groupType, ruleSetId })</code>). A <strong>blob bucket</strong> attaches one directly via its <code>ruleSetId</code>, where it governs member access per operation — see <a href="./blobs-and-files.html#access-presets">Blobs and Files</a>.</p><p>Two behaviors to know:</p><ul><li><strong>App owners and admins bypass rule-set evaluation</strong> — rules govern regular members.</li><li><strong>Types without a config row use permissive defaults</strong> (any member can create; the creator manages what they created). To deny an operation for everyone except admins, attach a rule set with that operation set to <code>&quot;false&quot;</code>.</li></ul><h2 id="testing-rules" tabindex="-1">Testing Rules <a class="header-anchor" href="#testing-rules" aria-label="Permalink to “Testing Rules”">​</a></h2><p>Rule sets are versioned and testable — evaluate rules against simulated requests before deploying:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Dry-run a rule set against a simulated scenario</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rule-sets</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">rule-set-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --scenario</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;user&quot;: {&quot;userId&quot;: &quot;u-1&quot;}}&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Trace an evaluation using real user and group data</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rule-sets</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> debug</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">userI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --group-type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> team</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --category</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> member</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --operation</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span></span></code></pre></div><p>The same is available from the client as <code>client.ruleSets.test()</code> and <code>client.ruleSets.debug()</code>. For database operations, the fastest loop is running the operation as different test users — see <a href="./primitive-cli.html#test-users-for-automated-testing">Test Users for Automated Testing</a>.</p><p><strong>Test gated states as a plain member.</strong> App owners and admins bypass most gates — workflow access rules, rule sets, metadata read/write rules, and bucket presets — so on those surfaces you can&#39;t exercise a locked or entitlement-gated state while signed in as one: a paywalled feature reads as open to an admin even when the gate is correct. Database operation <code>access</code> rules are the exception — they are evaluated for every caller, admins included. Verify that a gate actually denies using a <code>member</code> test user.</p><h2 id="trusting-external-identifiers" tabindex="-1">Trusting External Identifiers <a class="header-anchor" href="#trusting-external-identifiers" aria-label="Permalink to “Trusting External Identifiers”">​</a></h2><p>When the server later acts on an identifier — opening a billing portal from a payment <code>customer_id</code>, calling a provider API on a user&#39;s behalf — it must not trust a value the client supplied. A user-writable document holding <code>customerId</code> is unsafe: a caller could substitute someone else&#39;s id and act on their account.</p><p>Keep the authoritative user-to-external-id mapping in a store only the server writes, with reads scoped to the owning user:</p><ul><li><strong>Writes come from server-side automation only.</strong> Gate the write operation to the workflow that maintains the mapping — <code>access = &quot;fromWorkflow(&#39;billing-webhook&#39;)&quot;</code> — so no client can set it.</li><li><strong>Reads return only the caller&#39;s own row.</strong> Filter the read on <code>$user.userId</code>, so a caller can never name another user&#39;s id:</li></ul><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">operations</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;my-billing-profile&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">type = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;query&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">modelName = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;billingProfile&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">access = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;user.userId != &#39;&#39;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">operations</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">definition</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">filter = { userId = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$user.userId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><p>When a server action needs the external id, resolve it from the authenticated user through this operation — never accept it as a parameter from the client.</p><h2 id="patterns-that-hold-up" tabindex="-1">Patterns That Hold Up <a class="header-anchor" href="#patterns-that-hold-up" aria-label="Permalink to “Patterns That Hold Up”">​</a></h2><ol><li><strong>Default-deny, then open up.</strong> Start restrictive (<code>hasRole(&#39;admin&#39;)</code>) and widen deliberately. An operation with no rule and no <code>defaultAccess</code> is denied to every caller.</li><li><strong>One group type per concept.</strong> Separate <code>team</code>, <code>org</code>, and role-like types keep expressions readable: <code>isMemberOf(&#39;team&#39;, params.teamId) || isMemberOf(&#39;org&#39;, params.orgId)</code>.</li><li><strong>Membership over IDs.</strong> Manage <em>who&#39;s in the group</em>, not the rules — rules referencing groups rarely need to change.</li><li><strong>Parameterize the resource.</strong> Rules like <code>isMemberOf(&#39;team&#39;, params.teamId)</code> or <code>params.userId == user.userId</code> make one operation serve every team/user safely.</li></ol><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to “Next Steps”">​</a></h2><ul><li><strong><a href="./users-and-groups.html">Users and Groups</a></strong> — The groups your rules check membership against</li><li><strong><a href="./working-with-databases.html">Working with Databases</a></strong> — Operation-level rules in practice</li></ul>`,39)])])}const g=s(r,[["render",n]]);export{u as __pageData,g as default};
